.darma-loader-uiverse-shadow-hopper-dots {
  width: fit-content;
  height: fit-content;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.darma-loader-uiverse-shadow-hopper-dots__wrapper {
  width: 200px;
  height: 60px;
  position: relative;
  z-index: 1;
}

.darma-loader-uiverse-shadow-hopper-dots__circle {
width: 20px;
height: 20px;
position: absolute;
border-radius: 50%;
background-color: #fff;
left: 15%;
transform-origin: 50%;
animation: darma-loader-uiverse-shadow-hopper-dots-circle7124 .5s alternate infinite ease;
}

@keyframes darma-loader-uiverse-shadow-hopper-dots-circle7124 {
0% {
top: 60px;
height: 5px;
border-radius: 50px 50px 25px 25px;
transform: scaleX(1.7);
}

40% {
height: 20px;
border-radius: 50%;
transform: scaleX(1);
}

100% {
top: 0%;
}
}

.darma-loader-uiverse-shadow-hopper-dots__circle:nth-child(2) {
left: 45%;
animation-delay: .2s;
}

.darma-loader-uiverse-shadow-hopper-dots__circle:nth-child(3) {
left: auto;
right: 15%;
animation-delay: .3s;
}

.darma-loader-uiverse-shadow-hopper-dots__shadow {
width: 20px;
height: 4px;
border-radius: 50%;
background-color: rgba(0,0,0,0.9);
position: absolute;
top: 62px;
transform-origin: 50%;
z-index: -1;
left: 15%;
filter: blur(1px);
animation: darma-loader-uiverse-shadow-hopper-dots-shadow046 .5s alternate infinite ease;
}

@keyframes darma-loader-uiverse-shadow-hopper-dots-shadow046 {
0% {
transform: scaleX(1.5);
}

40% {
transform: scaleX(1);
opacity: .7;
}

100% {
transform: scaleX(.2);
opacity: .4;
}
}

.darma-loader-uiverse-shadow-hopper-dots__shadow:nth-child(4) {
left: 45%;
animation-delay: .2s
}

.darma-loader-uiverse-shadow-hopper-dots__shadow:nth-child(5) {
left: auto;
right: 15%;
animation-delay: .3s;
}

